void solve(int CASE)
{
	int n, m; cin >> n >> m;
	var c = vector<ll>(n + 1);
	fa(i, 1, n)cin >> c[i];
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}

	// 树形 dp 更新最小 c[u]
	var dfsc = [&](var dfs, int now, int fa)->void {
		if (g[now].size() == 1)return;

		// 取最小值次小值
		ll mn = LNF, cmn = LNF;
		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);
			if (mn > c[to]) {
				cmn = mn;
				mn = c[to];
			}
			else if (cmn > c[to])
				cmn = c[to];
		}
		c[now] = min(c[now], mn + cmn);
		};
	dfsc(dfsc, 1, 0);

	var p = Vec2<int>(n + 1, 31);
	var dp = Vec2<ll>(n + 1, 31);
	var dep = vector<int>(n + 1); // 判是否为祖先用

	// dfs 初始化 p[u][0] 和 dp[u][0]
	// 一次跳跃：u 跳到父节点，加上 u 权值最小的邻居 v 的权值
	// dp[u][0] = c[v]
	var dfs = [&](var dfs, int now, int fa)->void {
		dep[now] = dep[fa] + 1;
		p[now][0] = fa;

		// 取最小值次小值
		ll mn = LNF, cmn = LNF;
		for (int to : g[now]) {
			if (to == fa)continue;
			if (mn > c[to]) {
				cmn = mn;
				mn = c[to];
			}
			else if (cmn > c[to])
				cmn = c[to];
		}

		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);

			// 处理 to 节点和他的邻居
			if (c[to] == mn)dp[to][0] = cmn; 
			else dp[to][0] = mn;
		}
		};
	dfs(dfs, 1, 0);

	fa(j, 1, 30) {
		fa(i, 1, n) {
			p[i][j] = p[p[i][j - 1]][j - 1];
			dp[i][j] = dp[i][j - 1] + dp[p[i][j - 1]][j - 1];
		}
	}

	while (m--) {
		int x, y; cin >> x >> y;
		if (dep[x] <= dep[y]) {
			cout << -1 << endl;
			continue;
		}

		int now = x;
		ll ans = 0;
		fb(i, 30, 0) if (p[now][i] and dep[p[now][i]] >= dep[y]) {
			ans += dp[now][i];
			now = p[now][i];
		}
		if (now != y)cout << -1 << endl;
		else cout << ans << endl;
	}
	return;
}
